const articles = $('Query Drafts').all();
const publishers = $('Query Publishers').all();
const pubMap = {};
for (const p of publishers) pubMap[p.json.id] = p.json;

const edgeFnUrl = 'https://pbvjsixlqnuzcnqahbxu.supabase.co/functions/v1/blog-approval';
const results = [];

for (const item of articles) {
  const a = item.json;
  const pub = pubMap[a.publisher] || {};
  const content = a.content || '';
  const sources = a.sources || '';
  const imageMatch = sources.match(/Imagem: (.+?) \| Foto por (.+?) \((.+?)\) via Unsplash/);
  const plainText = content.replace(/<[^>]+>/g, '');
  const wordCount = (plainText.match(/\S+/g) || []).length;
  const hasWarning = content.includes('REVIEW_WARNING');
  const langBadge = pub.language === 'english'
    ? '<span style="background:#dbeafe;color:#1e40af;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;">EN</span>'
    : '<span style="background:#dcfce7;color:#166534;padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;">PT-BR</span>';
  const warning = hasWarning
    ? '<div style="background:#fff8e1;border-left:4px solid #f59e0b;padding:12px 20px;font-size:13px;color:#92400e;">⚠️ <strong>Atenção:</strong> a revisão técnica identificou problemas. Verifique antes de aprovar.</div>'
    : '';
  const approveUrl = `${edgeFnUrl}?token=${a.approval_token}&action=approve`;
  const rejectUrl = `${edgeFnUrl}?token=${a.approval_token}&action=reject`;
  const imageUrl = imageMatch ? imageMatch[1] : '';
  const photographer = imageMatch ? imageMatch[2] : '';
  const photographerUrl = imageMatch ? imageMatch[3] : '';
  const imageBlock = imageUrl
    ? `<img src="${imageUrl}" alt="${a.title}" style="width:100%;max-height:300px;object-fit:cover;display:block;" /><div style="padding:6px 32px;background:#f8fafc;border-bottom:1px solid #e2e8f0;font-size:11px;color:#94a3b8;">Foto por <a href="${photographerUrl}" style="color:#94a3b8;">${photographer}</a> via Unsplash</div>`
    : '';

  const emailHtml = `<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;padding:20px;background:#f4f4f5;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;"><div style="max-width:640px;margin:0 auto;background:#fff;border-radius:10px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,.08);"><div style="background:#0f172a;padding:24px 32px;"><div style="font-size:11px;font-weight:600;letter-spacing:1px;text-transform:uppercase;color:#94a3b8;margin-bottom:6px;">Blog Luby — Novo post para aprovação</div><div style="font-size:22px;font-weight:700;color:#f8fafc;line-height:1.3;">${a.title}</div></div><div style="padding:12px 32px;background:#f8fafc;border-bottom:1px solid #e2e8f0;font-size:12px;color:#64748b;">📡 <strong style="color:#334155">${pub.channel || ''}</strong> · 👤 <strong style="color:#334155">${pub.name || ''}</strong> · ${langBadge} · 📝 ~${wordCount} palavras</div>${warning}${imageBlock}<div style="padding:28px 32px;border-bottom:1px solid #e2e8f0;"><div style="font-size:11px;font-weight:600;letter-spacing:1px;text-transform:uppercase;color:#94a3b8;margin-bottom:12px;">Conteúdo completo</div><div style="font-size:15px;line-height:1.7;color:#374151;">${content}</div></div><div style="padding:32px;text-align:center;"><div style="font-size:14px;color:#64748b;margin-bottom:24px;">O conteúdo foi gerado automaticamente. Escolha uma ação:</div><a href="${approveUrl}" style="display:inline-block;padding:14px 32px;background:#16a34a;color:#fff;border-radius:7px;font-size:15px;font-weight:600;text-decoration:none;margin:0 8px;">✅ Aprovar e Publicar</a> <a href="${rejectUrl}" style="display:inline-block;padding:14px 32px;background:#f1f5f9;color:#334155;border:1px solid #cbd5e1;border-radius:7px;font-size:15px;font-weight:600;text-decoration:none;margin:0 8px;">🔄 Gerar Nova Versão</a></div><div style="padding:16px 32px;background:#f8fafc;border-top:1px solid #e2e8f0;text-align:center;font-size:11px;color:#94a3b8;">Blog Luby Auto · ${new Date().toISOString().split('T')[0]} · Artigo #${a.id}</div></div></body></html>`;

  results.push({
    json: {
      article_id: a.id,
      title: a.title,
      channel: pub.channel || 'unknown',
      emailSubject: `[Blog Luby] Novo post para aprovação: ${a.title}`,
      emailHtml: emailHtml
    }
  });
}
return results;
